 44→        {text: '去设置', onPress: () => navigation.navigate('Settings')},
 45→      ]);
 46→      return;
 47→    }
 48→
 49→    setLoading(true);
 50→    try {
 51→      setStatus(`正在转写录音 (${ASR_PROVIDERS[config.asrProvider].name})...`);
 52→      const audioText = await transcribeAudio(audioFile.uri, config);
 53→
 54→      setStatus('正在解析文档...');
 55→      const paragraphs = await parseDocx(docFile.uri);
 56→      const docText = paragraphsToText(paragraphs);
 57→
 58→      setStatus(`正在对比内容 (${LLM_PROVIDERS[config.llmProvider].name})...`);
 59→      const result = await compareTexts(audioText, docText, config);
 60→
 61→      setStatus('正在生成对比文档...');
 62→      const outputPath = await generateDiffDocx(docFile.uri, result.diffs);
 63→
 64→      setLoading(false);
 65→      setStatus('');
 66→      navigation.navigate('Result', {
 67→        outputPath, summary: result.summary,
 68→        diffCount: result.diffs.length, audioText, docText,
 69→      });
 70→    } catch (e: any) {
 71→      setLoading(false);
 72→      setStatus('');
 73→      Alert.alert('处理失败', e.message);
 74→    }
 75→  }, [audioFile, docFile, navigation]);
 76→
 77→  return (
 78→    <View style={styles.container}>
 79→      <Text style={styles.title}>选择文件</Text>
 80→      <TouchableOpacity style={styles.fileBtn} onPress={pickAudio}>
