113→// 百度ASR获取Token
114→async function getBaiduToken(apiKey: string, secretKey: string): Promise<string> {
115→  const url = `https://aip.baidubce.com/oauth/2.0/token?grant_type=client_credentials&client_id=${apiKey}&client_secret=${secretKey}`;
116→  const response = await fetch(url, {
117→    method: 'POST',
118→    headers: {'Content-Type': 'application/json', 'Accept': 'application/json'}
119→  });
120→  const data = await response.json();
121→
122→  if (data.error) {
123→    throw new Error(`百度认证失败: ${data.error_description || data.error}`);
124→  }
125→  if (!data.access_token) {
126→    throw new Error('百度认证失败: 未获取到access_token');
127→  }
128→  return data.access_token;
129→}
