132→export async function testAsrConnection(providerId: AsrProviderId, keyConfig: any): Promise<{ok: boolean; msg: string}> {
133→  try {
134→    if (!keyConfig?.key) return {ok: false, msg: '未填写API Key'};
135→
136→    switch (providerId) {
137→      case 'aliyun':
138→        if (!keyConfig.secret || !keyConfig.appKey) return {ok: false, msg: '请填写AccessKey Secret和AppKey'};
139→        return {ok: true, msg: '配置格式正确，将在实际转写时验证'};
140→
141→      case 'baidu':
142→        if (!keyConfig.secret) return {ok: false, msg: '请填写Secret Key'};
143→        // 实际验证百度凭据
