50→export async function getConfig(): Promise<AppConfig> {
51→  const raw = await AsyncStorage.getItem(CONFIG_KEY);
52→  if (!raw) return DEFAULT_CONFIG;
53→  try {
54→    return {...DEFAULT_CONFIG, ...JSON.parse(raw)};
55→  } catch {
56→    return DEFAULT_CONFIG;
57→  }
58→}
59→
60→export async function saveConfig(config: AppConfig) {
61→  await AsyncStorage.setItem(CONFIG_KEY, JSON.stringify(config));
62→}
63→
64→export function isConfigValid(config: AppConfig): boolean {
65→  const asrKey = config.asrKeys[config.asrProvider];
66→  const llmKey = config.llmKeys[config.llmProvider];
67→  return !!(asrKey?.key && llmKey?.key);
